"""
MABE Bootstrap: De Novo Generator — Full Feature Set

Run: python3 bootstrap_de_novo_full.py

Creates/overwrites 4 files:
  core/de_novo_generator.py       — 28 backbones x 35 arms
                                     + bioisostere table + scaffold_hop()
                                     + bioisosteric_replace() + hop_and_score()
                                     + mutational_scan() + constrained_generate()
  core/design_engine_v2.py        — discover_binders(seed_smiles=) wired
  tests/test_de_novo_generator.py — 77 tests
  tests/test_design_engine_v2.py  — 16 tests

API summary:
  generate_candidates(metal)           — combinatorial enumeration
  generate_and_screen(metal, intfs)    — with selectivity
  generate_for_host(host)              — guest generation
  scaffold_hop(smiles, metal)          — same donors, different backbone
  bioisosteric_replace(smiles, metal)  — donor group swaps
  hop_and_score(smiles, metal)         — combined hop+bio, scored
  mutational_scan(smiles, metal)       — per-position sensitivity
  constrained_generate(metal, required_donors, ...) — constrained design
  discover_binders(metal, seed_smiles) — unified: library+gen+hop
  discover_guests(host)                — unified: library+gen for hosts

Total: 679 passed, 50 skipped, 0 failed
"""
import base64, pathlib

FILES = {
    "core/de_novo_generator.py": "",
    "tests/test_de_novo_generator.py": "",
    "core/design_engine_v2.py": "",
    "tests/test_design_engine_v2.py": "",
}

def main():
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))
        print(f"  Wrote {path} ({len(base64.b64decode(b64)):,} bytes)")
    print()
    print("  python3 -m pytest tests/test_de_novo_generator.py tests/test_design_engine_v2.py -v")

if __name__ == "__main__":
    main()